VALUES
  ('real-estate-moex-01282', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '《史記•魏公子列傳》：「公子留趙十年不歸。秦聞公子在趙，日夜出兵東伐魏。魏王患之，使 使往請公子。公子恐其怒之，乃誡門下：『有敢為魏王使通者，死。』賓客皆背魏之趙，莫敢勸 公子歸。毛公、薛公兩人往見公子曰：『公子所以重於趙，名聞諸侯者，徒以有魏也。今秦攻魏， 魏急而公子不恤，使秦破大梁而夷先王之宗廟，公子當何面目立天下乎？』語未及卒，公子立變 色，告車趣駕歸救魏。」何以留趙十年不歸的魏公子，會立刻趕回魏國？ 怕魏王發怒    秦軍已經攻入魏都大梁 不想當一個見死不救的人  了解國家滅亡，個人就無立足之地', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01283', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「齊宣王好射，說人之謂己能則彊弓也。其嘗所用不過三石，以示左右，左右皆試引之，中關而 止，皆曰：『此不下九石，非王其孰能用是。』宣王之情，所用不過三石，而終身自以為用九石， 豈不悲哉？」（《呂氏春秋》）根據上文，下列選項最接近文意的是： 知人者智，自知者明   處世戒多言，言多必失 是非只為多開口，煩惱皆因強出頭  舉世皆濁我獨清，眾人皆醉我獨醒', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
